operations.insert:
/* Hide redundant pallet result heading text */
.results-head > div:first-child {
  display: none !important;
}

.results-head {
  justify-content: flex-end !important;
}

operations.old:
pendingPalletConfirmation = "";
hideWorkflowModal();
setStatus("Re-check started for completed pallet " + palletId + ". Scan SKU/EAN codes again.", "info");
startScanWorkflow(rows, palletId);

operations.new:
pendingPalletConfirmation = "";
hideWorkflowModal();
revisitNotice.textContent = "";
revisitNotice.classList.remove("active");
setStatus("Re-check started for completed pallet " + palletId + ". Scan SKU/EAN codes again.", "info");
startScanWorkflow(rows, palletId);
